#include <bits/stdc++.h>
using namespace std;

const int N=2010,mod=1e9+7;

struct Seg{
    int l,r;
    bool operator<(Seg x)const{
        return r<x.r;
    }
}seg[N];

int n,f[N][N],g[N][N*2],sf[N][N],sg[N][N*2],ans;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&seg[i].l,&seg[i].r);
    sort(seg+1,seg+n+1);
    for(int i=1;i<=n;i++){
        f[i][0]=1;
        for(int j=1;j<i;j++)
            f[i][j]=g[j][seg[i].l];
        sf[i][0]=1;
        for(int j=1;j<=n;j++) sf[i][j]=(sf[i][j-1]+f[i][j])%mod;
        int p=lower_bound(seg+1,seg+n+1,(Seg){0,seg[i].l})-seg-1;
        for(int j=1,k=0;j<=seg[i].r;j++){
            while(seg[k+1].r<j) k++;
            g[i][j]=(sf[i][k]+sg[p][j])%mod;
        }
        for(int j=0;j<=seg[n].r;j++) sg[i][j]=(sg[i-1][j]+g[i][j])%mod;
        ans=(ans+sf[i][n])%mod;
    }
    printf("%d",ans);
    return 0;
}
